package com.ecommerce.model;
import jakarta.persistence.*;import lombok.*;import org.springframework.data.annotation.CreatedDate;import org.springframework.data.jpa.domain.support.AuditingEntityListener;import java.math.BigDecimal;import java.time.LocalDateTime;import java.util.*;
@Entity @Table(name="products") @Data @Builder @NoArgsConstructor @AllArgsConstructor @EntityListeners(AuditingEntityListener.class)
public class Product { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false) private String name; @Column(columnDefinition="TEXT") private String description; @Column(nullable=false,precision=10,scale=2) private BigDecimal price; @Column(name="discount_price",precision=10,scale=2) private BigDecimal discountPrice; @Column(nullable=false) @Builder.Default private Integer stock=0; @ManyToOne(fetch=FetchType.LAZY) @JoinColumn(name="category_id") @ToString.Exclude @EqualsAndHashCode.Exclude private Category category; @OneToMany(mappedBy="product",cascade=CascadeType.ALL,orphanRemoval=true,fetch=FetchType.LAZY) @ToString.Exclude @EqualsAndHashCode.Exclude @Builder.Default private List<ProductImage> images=new ArrayList<>(); @OneToMany(mappedBy="product",cascade=CascadeType.ALL,fetch=FetchType.LAZY) @ToString.Exclude @EqualsAndHashCode.Exclude @Builder.Default private List<Review> reviews=new ArrayList<>(); @CreatedDate @Column(updatable=false) private LocalDateTime createdAt; private LocalDateTime updatedAt; @PreUpdate protected void onUpdate(){updatedAt=LocalDateTime.now();} }
